SELECT AVG(tabindex) AS average_tabindex
FROM captcha_configurations
WHERE sitekey = 'your_sitekey_here';

SELECT COUNT(DISTINCT user_id) AS failed_users_count
FROM captcha_interactions
WHERE action = 'failed';

SELECT COUNT(*) as NumberOfActiveSitekeys
FROM sitekeys
WHERE status = 'active';

SELECT sitekey, user_id
FROM captcha_interactions
WHERE action = 'failed';

SELECT COUNT(*) AS UserInteractionCount
FROM captcha_interactions
WHERE sitekey = '1';

SELECT *
FROM captcha_configurations
WHERE difficulty = 'hard';

SELECT DISTINCT ci.ip_address
FROM captcha_interactions ci
WHERE ci.sitekey = '0';
